export const DICT: Record<UiLanguage, Record<TKey, string>> = { en, vi };

export function translate(lang: UiLanguage, key: TKey, params?: TParams): string {
  const template = DICT[lang][key] ?? DICT.en[key] ?? key;
  if (!params) return template;
  return Object.keys(params).reduce(
    (acc, name) => acc.replace(new RegExp(`\\{${name}\\}`, "g"), String(params[name])),
    template,
  );
}
